class Solution {
public:
    int maximumXOR(vector<int>& nums) {
        int res = 0, mask = 0;
        for (int num : nums) {
            res = res | (res ^ num);
            mask |= (1 << (31 - __builtin_clz(res ^ num)));
        }
        return res;
    }
};
